import React, { useState, useRef } from 'react';

const Journal = () => {
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');
  const [entry, setEntry] = useState('');
  const textareaRef = useRef();

  function autoResizeTextarea() {
    const textarea = textareaRef.current;
    if (textarea) {
      textarea.style.height = 'auto'; // reset height
      textarea.style.height = textarea.scrollHeight + 'px'; // set new height
    }
  }

  const handleAnalyze = async () => {
    if (!entry.trim()) return;

    const newEntry = {
      title,
      date: date || new Date().toLocaleDateString(),
      entry,
    };

    const prev = JSON.parse(localStorage.getItem('journalEntries')) || [];
    localStorage.setItem('journalEntries', JSON.stringify([...prev, newEntry]));

    try {
      const res = await fetch("http://localhost:5001/api/ai/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: entry })
      });

      const data = await res.json();
      console.log("API response:", data); // DEBUG

      if (data.all_scores && data.all_scores.length) {
        const topEmotions = data.all_scores
          .sort((a, b) => b.score - a.score)
          .slice(0, 3)
          .map(e => `${e.label} (${(e.score * 100).toFixed(1)}%)`)
          .join(', ');
        alert(`Top Emotions: ${topEmotions}`);
      } else if (data.error) {
        alert(`Emotion analysis error: ${data.error}`);
      } else {
        alert("Emotion analysis failed. Try again.");
      }



      setTitle('');
      setDate('');
      setEntry('');
    } catch (error) {
      console.error("Error analyzing entry:", error);
      alert("Error analyzing entry. Check console.");
    }
  };


  return (
    <>
      <div className="journal-page">
        <h1 className="journal-heading">Journal Page</h1>
        <div className="journal-header">
          <input
            className="journal-title"
            placeholder="Title (optional)"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <input
            className="journal-date"
            placeholder="dd/mm/yyyy"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </div>

        <div className="journal-body">
          <textarea
            ref={textareaRef}
            className="journal-entry"
            placeholder="Write your journal entry here..."
            value={entry}
            //                      onChange={(e) => {
            //   setEntry(e.target.value);
            //   autoResizeTextarea();
            // }}
            onChange={(e) => setEntry(e.target.value)}
          />
        </div>

        <div className="journal-footer">
          <button className="journal-analyze" onClick={handleAnalyze}>
            Add
          </button>
          <button className="journal-analyze">
            Analyze
          </button>
        </div>

        <Stylesheet />
      </div>
    </>
  );
};

